import json
from typing import Dict, List, Any, Optional

# Strings pour true/false
true = True
false = False
null = None

def extract_observable(analyzer_result: Dict[str, Any]) -> Optional[str]:
    """Extrait l'observable du résultat selon le type d'analyzer."""
    try:
        # L'observable est dans le champ 'data' à la racine
        observable = analyzer_result.get('data', None)
        if observable:
            return str(observable).strip()

        # Fallback : chercher dans report.full
        report = analyzer_result.get('report', {})
        full = report.get('full', {})

        # Pour VirusTotal
        if 'attributes' in full:
            observable_type = full.get('type', '')
            attributes = full.get('attributes', {})

            if observable_type == 'url':
                return attributes.get('url')
            elif observable_type == 'file':
                return full.get('id') or attributes.get('sha256')
            elif observable_type == 'domain':
                return full.get('id')
            elif observable_type == 'ip_address':
                return full.get('id')

        # Pour AbuseIPDB
        values = full.get('values', [])
        if values and len(values) > 0:
            data = values[0].get('data', {})
            return data.get('ipAddress')

        # Pour MalwareBazaar
        data = full.get('data', {})
        if 'sha256_hash' in data:
            return data.get('sha256_hash')

        # Pour URLScan.io
        if 'query' in full:
            query = full.get('query', '')
            return query.strip('"').strip("'")

        return None

    except Exception as e:
        return None

def extract_score_and_namespace(taxonomies: List[Dict[str, Any]]) -> tuple:
    """Extrait le score et le namespace principal des taxonomies."""
    if not taxonomies:
        return None, None

    for taxonomy in taxonomies:
        namespace = taxonomy.get('namespace', '')
        value = taxonomy.get('value')
        predicate = taxonomy.get('predicate', '')

        # VirusTotal : format "X/Y"
        if namespace == 'VT' and isinstance(value, str) and '/' in str(value):
            return str(value), namespace

        # AbuseIPDB : Abuse Confidence Score
        if namespace == 'AbuseIPDB' and predicate == 'Abuse Confidence Score':
            return str(value), namespace

        # MalwareBazaar : Signature
        if namespace == 'MalwareBazaar':
            return str(value) if value else 'Detected', namespace

        # URLScan.io : Overall Score
        if namespace == 'urlscan.io' and 'Score' in predicate:
            if isinstance(value, str) and ':' in value:
                score_part = value.split(':')[1]
                return score_part, namespace
            return str(value), namespace

    # Retourner la première valeur
    first = taxonomies[0]
    return str(first.get('value')), first.get('namespace')

def is_not_found_result(report: Dict[str, Any], taxonomies: List[Dict[str, Any]]) -> bool:
    """
    Vérifie si le résultat indique que l'observable n'a pas été trouvé.
    Retourne True si c'est un résultat "not found" à ignorer.
    """
    full = report.get('full', {})

    # MalwareBazaar : query_status == "hash_not_found"
    query_status = full.get('query_status', '')
    if query_status in ('hash_not_found', 'no_results', 'not_found'):
        return True

    # Vérifier les taxonomies pour "No results", "Not Found", etc.
    not_found_values = [
        'no results', 'not found', 'no result', 'none', 
        'no matches', 'no match', 'unknown', 'n/a'
    ]

    for taxonomy in taxonomies:
        value = str(taxonomy.get('value', '')).lower().strip()
        predicate = str(taxonomy.get('predicate', '')).lower()

        # Si la valeur indique "not found"
        if value in not_found_values:
            return True

        # MalwareBazaar spécifique : predicate "Search" avec value "No results"
        if predicate == 'search' and value == 'no results':
            return True

    # VirusTotal : vérifier si le fichier/URL existe vraiment
    # Si response_code indique non trouvé
    response_code = full.get('response_code', 1)
    if response_code == 0:
        return True

    # AbuseIPDB : pas de données
    if not full.get('data') and not full.get('values') and 'abuseConfidenceScore' not in str(full):
        # Vérifier si c'est vraiment AbuseIPDB sans résultat
        for taxonomy in taxonomies:
            if taxonomy.get('namespace') == 'AbuseIPDB':
                return True

    return False


def reformat_cortex_results(raw_results: List[Dict[str, Any]]) -> Dict[str, Any]:
    """
    Reformate les résultats Cortex en structure simplifiée.
    """
    valid_reports = []
    level_counts = {
        'malicious': 0,
        'suspicious': 0,
        'safe': 0,
        'info': 0
    }

    for result in raw_results:
        # Vérifier le status (Success ou Failure)
        status = result.get('status', '')
        if status != 'Success':
            continue

        # Vérifier si report.success = true
        report = result.get('report', {})
        if not report.get('success', False):
            continue

        # Vérifier si c'est une erreur
        if 'errorMessage' in report or 'errorMessage' in result:
            continue

        # Extraire les informations
        summary = report.get('summary', {})
        taxonomies = summary.get('taxonomies', [])

        # Si pas de taxonomies, skip
        if not taxonomies:
            continue

        # *** NOUVEAU : Vérifier si c'est un résultat "not found" ***
        if is_not_found_result(report, taxonomies):
            continue

        # Extraire l'observable
        observable = extract_observable(result)
        if not observable:
            continue

        # Extraire le score et la source
        score, namespace = extract_score_and_namespace(taxonomies)

        # Déterminer le level (prendre le plus critique)
        level = 'info'
        for taxonomy in taxonomies:
            tax_level = taxonomy.get('level', 'info')
            if tax_level == 'malicious':
                level = 'malicious'
                break
            elif tax_level == 'suspicious' and level != 'malicious':
                level = 'suspicious'
            elif tax_level == 'safe' and level == 'info':
                level = 'safe'

        # Compter par niveau
        if level in level_counts:
            level_counts[level] += 1

        # Créer l'entrée formatée
        formatted_entry = {
            'observable': observable,
            'source': namespace if namespace else 'Unknown',
            'score': score if score is not None else 'N/A',
            'level': level
        }

        valid_reports.append(formatted_entry)

    # Créer le résultat final
    output = {
        'valid_cortex_reports': valid_reports,
        'total_cortex_received': len(raw_results),
        'total_cortex_found': len(valid_reports),  # Renommé pour clarté
        'malicious_count': level_counts['malicious'],
        'suspicious_count': level_counts['suspicious'],
        'safe_count': level_counts['safe'],
        'info_count': level_counts['info']
    }

    return output


